export function sortSongsByFieldB(songs: Record<string, string>[], field: string, asc: boolean): Record<string, string>[] {
  const list = songs.slice()
  list.sort((a, b) => {
    const va = a[field] ?? ''
    const vb = b[field] ?? ''
    let r = 0
    if (va < vb) {
      r = -1
    } else if (va > vb) {
      r = 1
    }
    return asc ? r : -r
  })
  return list
}

