export function capitalizeWordsB11(text: string): string {
  const words = text.split(' ')
  const out: string[] = []
  for (const w of words) {
    if (w.length === 0) {
      out.push(w)
    } else {
      out.push(w.charAt(0).toUpperCase() + w.substring(1))
    }
  }
  return out.join(' ')
}

